# compute longest common substring length
def longest_common_substring(a,b):
    n, m = len(a), len(b)
    dp = [[0]*(m+1) for _ in range(n+1)]
    lcs_len = 0
    for i in range(1,n+1):
        for j in range(1,m+1):
            if a[i-1] == b[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
                if dp[i][j] > lcs_len:
                    lcs_len = dp[i][j]
            # else dp[i][j] = 0
    return lcs_len

